package eligibility

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"time"

	"github.com/utilitywarehouse/uwos-go/telemetry/tracing"
	"github.com/utilitywarehouse/uwos-go/telemetry/uwconv"
	"go.opentelemetry.io/otel/attribute"
	"go.opentelemetry.io/otel/trace"

	"github.com/utilitywarehouse/telecom-mobile/pkg/handseteligibility"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tlog"
)

// Client is an HTTP client for the third-party eligibility provider.
type Client struct {
	httpClient *http.Client
	baseURL    string
	authToken  string
}

// NewClient creates a new eligibility client.
func NewClient(baseURL, authToken string, timeout time.Duration) *Client {
	return &Client{
		httpClient: &http.Client{
			Timeout: timeout,
		},
		baseURL:   baseURL,
		authToken: authToken,
	}
}

// RequestEligibilityCheck sends an eligibility check request to the third-party provider.
// This is called asynchronously after contract creation — the provider will respond
// via the EligibilityCallback endpoint.
func (c *Client) RequestEligibilityCheck(ctx context.Context, req handseteligibility.EligibilityRequest) error {
	ctx, span := tracing.Tracer().Start(ctx, "EligibilityCheck", trace.WithAttributes(
		attribute.String("request_id", req.RequestID),
		attribute.String("handset_id", req.HandsetID),
		uwconv.CustomerAccountID(req.CustomerID),
	))
	defer span.End()

	body, err := json.Marshal(req)
	if err != nil {
		_ = tracing.RecordSpanError(span, err)
		return fmt.Errorf("failed to marshal eligibility request: %w", err)
	}

	url := fmt.Sprintf("%s/eligibility/check", c.baseURL)
	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, url, bytes.NewReader(body))
	if err != nil {
		_ = tracing.RecordSpanError(span, err)
		return fmt.Errorf("failed to create eligibility request: %w", err)
	}

	httpReq.Header.Set("Content-Type", "application/json")
	if c.authToken != "" {
		httpReq.Header.Set("Authorization", fmt.Sprintf("Bearer %s", c.authToken))
	}

	resp, err := c.httpClient.Do(httpReq)
	if err != nil {
		_ = tracing.RecordSpanError(span, err)
		return fmt.Errorf("failed to send eligibility request: %w", err)
	}
	defer func() {
		if closeErr := resp.Body.Close(); closeErr != nil {
			tlog.Error(ctx, "failed to close eligibility response body: %v", closeErr)
		}
	}()

	span.SetAttributes(attribute.Int("http.status_code", resp.StatusCode))

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		respBody := "none"
		if rb, err := io.ReadAll(resp.Body); err == nil {
			respBody = string(rb)
		}
		respErr := fmt.Errorf("eligibility provider returned status %d: %s", resp.StatusCode, respBody)
		_ = tracing.RecordSpanError(span, respErr)
		return respErr
	}

	return nil
}

