	"io"
	"sort"

	"gopkg.in/yaml.v1"

	"github.com/utilitywarehouse/telecom-mobile/pkg/handsetdb/assets"
)

var ErrNotFound = errors.New("err not found")

// HandsetConfigFileName is the name of the YAML file containing handset data.
// This was last updated 2023-10-18
const HandsetConfigFileName = "handsets.yaml"

type handsetDB struct {
	handsetIdToHandset map[string]Handset
	allHandsets        []*Handset
}

//go:generate mockgen -package=handsetdbmock -destination=mocks/handsetmock.go github.com/utilitywarehouse/telecom-mobile/pkg/handsetdb DB
type DB interface {
	GetByHandsetId(handsetId string) (*Handset, error)
	GetAllHandsets(isActive *bool) []*Handset
}

func LoadDBFromFile(f io.Reader) (DB, error) {
	b, err := io.ReadAll(f)
	if err != nil {
		return nil, fmt.Errorf("failed to read handsets: %w", err)
	}
	var ts []Handset
	err = yaml.Unmarshal(b, &ts)
	if err != nil {
		return nil, fmt.Errorf("failed to unmarshal handsets: %w", err)
	}

	handsetIdToHandset := make(map[string]Handset)
	var allHandsets []*Handset
	for _, t := range ts {
		handsetIdToHandset[t.ID] = t
		cp := t
		allHandsets = append(allHandsets, &cp)
	}
	sort.Slice(allHandsets, func(i, j int) bool {
		return allHandsets[i].Name < allHandsets[j].Name
	})

	return &handsetDB{
		handsetIdToHandset: handsetIdToHandset,
		allHandsets:        allHandsets,
	}, nil
}

func LoadDB() (DB, error) {
	f, err := assets.Static.Open(HandsetConfigFileName)
	if err != nil {
		return nil, fmt.Errorf("failed to open handsets: %w", err)
