//}

func initUnicomClient(ctx context.Context, unicomAddr string) (unicomservice.UnicomClient, *uwgrpc.ClientConn, machine.Provider) {
	machineToken, err := tiam.GetNewMachineToken()
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "error while requesting machine token")
	}

	options := tgrpc.GetDefaultDialOptions()
	options.AddOptions(uwgrpc.WithDialIAM(iam.WithMachine(machineToken)))

	unicomConn, err := tgrpc.InitGRPCConnection(ctx, unicomAddr, options)
	if err != nil {
		tlog.WithError(err).
			WithAttribute("address", unicomAddr).
			Fatal(ctx, "could not dial grpc server")
	}
	return unicomservice.NewUnicomClient(unicomConn), unicomConn, machineToken
}

