	time := utils.TimestampbbToString(res.GetTime())

	toModelStatus := func(val porting_out_events.AuthCodeStatus) *sharedmodel.MobilePortingOutAuthCodeStatus {
		switch val {
		case porting_out_events.AuthCodeStatus_AUTH_CODE_STATUS_GENERATED:
			st := sharedmodel.MobilePortingOutAuthCodeStatusAuthCodeStatusGenerated
			return &st
		case porting_out_events.AuthCodeStatus_AUTH_CODE_STATUS_UNKNOWN:
			st := sharedmodel.MobilePortingOutAuthCodeStatusAuthCodeStatusUnknown
			return &st
		case porting_out_events.AuthCodeStatus_AUTH_CODE_STATUS_CONFLICT:
			st := sharedmodel.MobilePortingOutAuthCodeStatusAuthCodeStatusUw // not entirely sure about this one
			return &st
		case porting_out_events.AuthCodeStatus_AUTH_CODE_STATUS_RETRIEVED:
			st := sharedmodel.MobilePortingOutAuthCodeStatusAuthCodeStatusRetrieved
			return &st
		default:
			st := sharedmodel.MobilePortingOutAuthCodeStatusAuthCodeStatusUnknown
			return &st
		}
	}

	toModelBusinessUnit := func(bu porting_out_events.BusinessUnit) *sharedmodel.MobileBusinessUnit {
		switch bu {
		case porting_out_events.BusinessUnit_BUSINESS_UNIT_UNKNOWN:
			b := sharedmodel.MobileBusinessUnitBusinessUnitUnknown
			return &b
		case porting_out_events.BusinessUnit_BUSINESS_UNIT_1P:
			b := sharedmodel.MobileBusinessUnitBusinessUnit1p
			return &b
		case porting_out_events.BusinessUnit_BUSINESS_UNIT_UW:
			b := sharedmodel.MobileBusinessUnitBusinessUnitUw
			return &b
		default:
			b := sharedmodel.MobileBusinessUnitBusinessUnitUnknown
			return &b
		}
	}

	etfAmount := res.GetEtf().GetAmount()
	etfCurrencyCode := res.GetEtf().GetCurrencyCode()
	authCode := res.GetAuthCode()
	cli := res.GetCli()
	correlationToken := res.GetCorrelationToken()
	id := res.GetId()
	rawCli := res.GetRawCli()

	toModelType := func(portType porting_out_events.Type) *sharedmodel.MobilePortingType {
		switch portType {
		case porting_out_events.Type_TYPE_STAC:
			pt := sharedmodel.MobilePortingTypePortTypeStac
			return &pt
		case porting_out_events.Type_TYPE_PAC:
			pt := sharedmodel.MobilePortingTypePortTypePac
			return &pt
		case porting_out_events.Type_TYPE_UNKNOWN:
			pt := sharedmodel.MobilePortingTypePortTypeUnknown
			return &pt
		default:
			pt := sharedmodel.MobilePortingTypePortTypeUnknown
			return &pt
		}
	}

	return &sharedmodel.MobilePortingOutState{
		AuthCode:         &authCode,
		AuthCodeExpiry:   &authCodeExpiry,
		AuthCodeStatus:   toModelStatus(res.GetAuthCodeStatus()),
		BusinessUnit:     toModelBusinessUnit(res.GetBusinessUnit()),
		Cli:              &cli,
		CorrelationToken: &correlationToken,
		Etf: &sharedmodel.MobileMoney{
			Amount:   etfAmount,
			Currency: etfCurrencyCode,
		},
		ID: &id,
		PrepayBalance: &sharedmodel.MobileMoney{
			Amount:   res.GetEtf().GetAmount(),
			Currency: res.GetEtf().GetCurrencyCode(),
		},
		RawCli:      &rawCli,
		RequestTime: &requestTime,
		Time:        &time,
		Type:        toModelType(res.GetType()),
	}
}

func (r *Resolver) map3DSActionResponse(action *topupapi.RequiredAction) *model.MobileTopupRequiredAction {
	if action == nil {
		return nil
	}

	return &model.MobileTopupRequiredAction{
		TransactionData:          new(string(action.GetTransactionData()[:])),
		ExternalTransactionToken: action.GetExternalTransactionToken(),
	}
}
func (r *Resolver) mapTopupFailureCode(failureCode *topupapi.FailureCode) *string {
	var output *string

	failureMessage := map[topupapi.FailureCode]string{
		topupapi.FailureCode_FAILURE_PAYMENT_REFUSED:            "Payment failed. For more information please contact your bank.",
		topupapi.FailureCode_FAILURE_PAYMENT_METHOD_NOT_ALLOWED: "Invalid payment method. Please try a different card.",
		topupapi.FailureCode_FAILURE_ADDRESS_CHECK_FAILED:       "Error: Payment details do not match.",
		topupapi.FailureCode_FAILURE_3DS_REFUSED:                "Authentication failed. Please try again.",
		topupapi.FailureCode_FAILURE_INVALID_PAYMENT_METHOD:     "Invalid card. Please check your details or try a different card.",
	}

	if failureCode != nil {
		msg := failureMessage[*failureCode]
		output = &msg
	}
	return output
}

func (r *Resolver) getOverrideAddress(req model.MobileSimReplacementRequest) *customer_events.BillCustomerAddress {
	if req.OverrideAddressLine1 == nil &&
		req.OverrideAddressLine2 == nil &&
		req.OverrideAddressLine3 == nil &&
		req.OverrideAddressLine4 == nil &&
		req.OverrideCounty == nil &&
		req.OverridePostCode == nil {
		return nil
	}

	return &customer_events.BillCustomerAddress{
		AddressLine_1: utils.PtrToString(req.OverrideAddressLine1),
		AddressLine_2: utils.PtrToString(req.OverrideAddressLine2),
		AddressLine_3: utils.PtrToString(req.OverrideAddressLine3),
		AddressLine_4: utils.PtrToString(req.OverrideAddressLine4),
		County:        utils.PtrToString(req.OverrideCounty),
		PostCode:      utils.PtrToString(req.OverridePostCode),
	}
}

